INSERT INTO messages (id, conversation_id, sender_id, content, sent_at, visibility) VALUES
    ('m0000010-0000-0000-0001-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'Salut Alice ! C''était cool hier au festival, content d''avoir fait ta connaissance. Au fait j''ai réalisé ce matin que je bosse avec Julien Maréchal — c''est pas ton pote ? Le monde est vraiment petit mdr', '2026-06-01 11:23:00+00', 'safe'),
    ('m0000010-0000-0000-0002-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'Attends QUOI 😭 t''es sérieux ?? Il m''a jamais parlé de toi lol. C''est ouf comme coïncidence', '2026-06-01 11:47:00+00', 'safe'),
    ('m0000010-0000-0000-0003-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'Haha grave, on est dans la même équipe depuis 8 mois. Je lui ai envoyé un message ce matin, il était choqué aussi', '2026-06-01 11:49:00+00', 'safe'),
    ('m0000010-0000-0000-0004-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'Mdr lui c''est un désastre pour présenter les gens entre eux. Bref bienvenue dans le cercle je suppose 😄', '2026-06-01 11:52:00+00', 'safe'),
    ('m0000010-0000-0000-0005-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'Haha merci ! Le festival c''était bien en tout cas. Le foodtruck thaï valait le déplacement', '2026-06-01 11:53:00+00', 'safe'),
    ('m0000010-0000-0000-0006-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'Carrément, j''ai regretté de pas avoir pris le double mdr. Bon je dois filer j''ai une réunion — à bientôt !', '2026-06-01 12:01:00+00', 'safe'),
    ('m0000010-0000-0000-0007-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'Bonne réunion 👋', '2026-06-01 12:02:00+00', 'safe'),
    ('m0000010-0000-0000-0008-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'c''est quoi ça ??', '2026-06-02 13:14:00+00', 'safe'),
    ('m0000010-0000-0000-0009-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'Haha le resto du midi. T''as vu le ratio protéines/prix c''est imbattable', '2026-06-02 13:15:00+00', 'safe'),
    ('m0000010-0000-0000-0010-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'lol t''as l''air de t''y connaître en bouffe pour quelqu''un qui a mis 20 min à choisir au festival samedi', '2026-06-02 13:17:00+00', 'safe'),
    ('m0000010-0000-0000-0011-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'CHEH. J''avais trop de choix c''est pas ma faute', '2026-06-02 13:18:00+00', 'safe'),
    ('m0000010-0000-0000-0012-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'ouais c''est ça 😂 t''es dans quel secteur du coup ? Julien m''a jamais vraiment dit ce que vous faisiez', '2026-06-02 13:20:00+00', 'safe'),
    ('m0000010-0000-0000-0013-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'Analyse data pour une boîte de logistique, c''est moins glamour que ça en a l''air mdr. Et toi ?', '2026-06-02 13:22:00+00', 'safe'),
    ('m0000010-0000-0000-0014-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'Communication pour une agence. Du coup on a le même niveau de glamour', '2026-06-02 13:25:00+00', 'safe'),
    ('m0000010-0000-0000-0015-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'Haha équité totale. Bon courage pour l''aprèm', '2026-06-02 13:26:00+00', 'safe'),
    ('m0000010-0000-0000-0016-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'Toi aussi 👍', '2026-06-02 13:27:00+00', 'safe'),
    ('m0000010-0000-0000-0017-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'Hey — j''ai demandé à Julien pourquoi il t''avait jamais présentée avant. Sa réponse était… intéressante', '2026-06-02 19:34:00+00', 'safe'),
    ('m0000010-0000-0000-0018-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', '??? il a dit quoi lol', '2026-06-02 19:41:00+00', 'safe'),
    ('m0000010-0000-0000-0019-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'Que t''étais "dans ta bulle avec Laurent ces derniers temps" mdr. Il t''a pas ratée', '2026-06-02 19:43:00+00', 'safe'),
    ('m0000010-0000-0000-0020-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'JULIEN 😭 il est impossible. C''est pas faux mais quand même', '2026-06-02 19:45:00+00', 'safe'),
    ('m0000010-0000-0000-0021-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'Haha non il a dit ça gentiment promis. Il parle souvent de toi en bien en fait', '2026-06-02 19:46:00+00', 'safe'),
    ('m0000010-0000-0000-0022-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'Mouais j''espère. C''est mon meilleur pote depuis le lycée donc si il disait du mal j''aurais un problème lol', '2026-06-02 19:48:00+00', 'safe'),
    ('m0000010-0000-0000-0023-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'Depuis le lycée c''est rare ça. Vous avez survécu à tout', '2026-06-02 19:50:00+00', 'safe'),
    ('m0000010-0000-0000-0024-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'Ouais… enfin on a eu nos moments compliqués mais ça tient. Il est chiant mais je l''aime bien quand même', '2026-06-02 19:52:00+00', 'safe'),
    ('m0000010-0000-0000-0025-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'C''est la définition exacte d''une bonne amitié', '2026-06-02 19:53:00+00', 'safe'),
    ('m0000010-0000-0000-0026-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', '😄 bon sur ce je vais manger, bonne soirée !', '2026-06-02 19:54:00+00', 'safe'),
    ('m0000010-0000-0000-0027-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'Bonne soirée 🙂', '2026-06-02 19:55:00+00', 'safe'),
    ('m0000010-0000-0000-0028-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 't''es où là c''est beau', '2026-06-03 18:05:00+00', 'safe'),
    ('m0000010-0000-0000-0029-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'Terrasse du bureau haha. On a une vue sympa au moins c''est ça', '2026-06-03 18:12:00+00', 'safe'),
    ('m0000010-0000-0000-0030-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'Ça compense les réunions interminables', '2026-06-03 18:13:00+00', 'safe'),
    ('m0000010-0000-0000-0031-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'Exactement ma philosophie de survie 😂', '2026-06-03 18:14:00+00', 'safe'),
    ('m0000010-0000-0000-0032-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'Dis, t''avais pas parlé du festival des Halles le mois prochain ? Julien m''a dit que vous y alliez potentiellement', '2026-06-03 20:47:00+00', 'safe'),
    ('m0000010-0000-0000-0033-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'Ouais j''y réfléchis, j''y suis allé l''an dernier c''était bien. Pourquoi tu veux y aller ?', '2026-06-03 20:51:00+00', 'safe'),
    ('m0000010-0000-0000-0034-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'Laurent veut pas trop les festivals donc je cherche des gens à convaincre de venir avec moi mdr', '2026-06-03 20:53:00+00', 'safe'),
    ('m0000010-0000-0000-0035-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'Ah bah si Julien y va on peut s''organiser tous ensemble, ça serait cool', '2026-06-03 20:55:00+00', 'safe'),
    ('m0000010-0000-0000-0036-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'Ouais carrément, je vais lui en parler', '2026-06-03 20:56:00+00', 'safe'),
    ('m0000010-0000-0000-0037-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'Il m''a dit que vous vous voyiez souvent le week-end ?', '2026-06-03 20:58:00+00', 'safe'),
    ('m0000010-0000-0000-0038-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'Pas toutes les semaines mais souvent. On fait des soirées jeux chez lui des fois, c''est devenu un truc régulier', '2026-06-03 21:00:00+00', 'safe'),
    ('m0000010-0000-0000-0039-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'Des soirées jeux c''est underrated comme concept. C''est quoi vos jeux ?', '2026-06-03 21:02:00+00', 'safe'),
    ('m0000010-0000-0000-0040-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'Codenames, Skull, Catan si on est courageux. Toi t''es joueur ?', '2026-06-03 21:03:00+00', 'safe'),
    ('m0000010-0000-0000-0041-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'Ouais grave, j''ai une honte totale pour Catan mdr. J''arrive jamais à m''allier correctement', '2026-06-03 21:05:00+00', 'safe'),
    ('m0000010-0000-0000-0042-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'HAHA c''est la BASE de Catan ! T''es le mec qui fait cavalier seul et qui finit 4e ?', '2026-06-03 21:06:00+00', 'safe'),
    ('m0000010-0000-0000-0043-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', '…je plaide le 5e', '2026-06-03 21:07:00+00', 'safe'),
    ('m0000010-0000-0000-0044-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', '😂😂😂 okay t''as du travail', '2026-06-03 21:08:00+00', 'safe'),
    ('m0000010-0000-0000-0045-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'Je suis ouvert aux formations', '2026-06-03 21:09:00+00', 'safe'),
    ('m0000010-0000-0000-0046-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'Je note. Prochain soirée jeux chez Julien je te passe l''info si t''as envie, ça peut être sympa', '2026-06-03 21:11:00+00', 'safe'),
    ('m0000010-0000-0000-0047-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'Carrément, j''attends l''invitation officielle', '2026-06-03 21:12:00+00', 'safe'),
    ('m0000010-0000-0000-0048-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'Elle arrivera 😄', '2026-06-03 21:13:00+00', 'safe'),
    ('m0000010-0000-0000-0049-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', '👌', '2026-06-03 21:14:00+00', 'safe'),
    ('m0000010-0000-0000-0050-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'Hey t''es encore dispo ? J''ai une question existentielle', '2026-06-03 22:38:00+00', 'safe'),
    ('m0000010-0000-0000-0051-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'lol oui quoi', '2026-06-03 22:44:00+00', 'safe'),
    ('m0000010-0000-0000-0052-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'Le foodtruck thaï du festival l''autre jour — t''avais pris quoi exactement ? J''essaie de retrouver le plat', '2026-06-03 22:45:00+00', 'safe'),
    ('m0000010-0000-0000-0053-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'HAHA c''est ça ton urgence ?? C''était le pad thaï crevettes je crois. Pourquoi', '2026-06-03 22:46:00+00', 'safe'),
    ('m0000010-0000-0000-0054-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'Parce que j''y pense encore et ça me ronge', '2026-06-03 22:47:00+00', 'safe'),
    ('m0000010-0000-0000-0055-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'mdr t''es dramatique. Cherche "pad thaï crevettes sauce tamarin" t''as toutes les recettes', '2026-06-03 22:48:00+00', 'safe'),
    ('m0000010-0000-0000-0056-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'Merci chef', '2026-06-03 22:49:00+00', 'safe'),
    ('m0000010-0000-0000-0057-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'De rien. Bonne nuit 😄', '2026-06-03 22:50:00+00', 'safe'),
    ('m0000010-0000-0000-0058-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'Bonne nuit !', '2026-06-03 22:51:00+00', 'safe'),
    ('m0000010-0000-0000-0059-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'Update : la recette était pas terrible. La recherche continue', '2026-06-04 14:22:00+00', 'safe'),
    ('m0000010-0000-0000-0060-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'mdr paix à ton estomac. Courage', '2026-06-04 14:38:00+00', 'safe'),
    ('m0000010-0000-0000-0061-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'ça fait bizarre de pas avoir de nouvelles de Julien depuis 2 jours, il répond plus', '2026-06-04 22:07:00+00', 'safe'),
    ('m0000010-0000-0000-0062-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'Haha il est en mode deadline cette semaine. Au bureau jusqu''à 20h tous les jours', '2026-06-04 22:09:00+00', 'safe'),
    ('m0000010-0000-0000-0063-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'Ah oui c''est vrai il m''avait dit… j''avais oublié. Au moins t''es au courant toi', '2026-06-04 22:10:00+00', 'safe'),
    ('m0000010-0000-0000-0064-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'J''ai le privilège de le voir stresser en direct, c''est fascinant', '2026-06-04 22:11:00+00', 'safe'),
    ('m0000010-0000-0000-0065-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'Pauvre Julien. Il stresse comment ? Il fait la tête ou il parle trop ?', '2026-06-04 22:12:00+00', 'safe'),
    ('m0000010-0000-0000-0066-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'Il parle trop. Beaucoup trop. Il a refait l''histoire complète de son projet 3 fois aujourd''hui', '2026-06-04 22:13:00+00', 'safe'),
    ('m0000010-0000-0000-0067-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'OH C''EST SI RECONNAISSABLE MDR. Il fait ça depuis le lycée — quand il stresse il raconte en boucle', '2026-06-04 22:14:00+00', 'safe'),
    ('m0000010-0000-0000-0068-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'T''as pas peur que je lui dise que tu te fous de lui ?', '2026-06-04 22:16:00+00', 'safe'),
    ('m0000010-0000-0000-0069-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'Non parce qu''il le sait déjà et il trouve ça normal 😂 On se dit tout', '2026-06-04 22:17:00+00', 'safe'),
    ('m0000010-0000-0000-0070-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'C''est une belle relation en fait', '2026-06-04 22:18:00+00', 'safe'),
    ('m0000010-0000-0000-0071-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'Ouais… je réalise pas toujours la chance que j''ai. Il est chiant et il parle trop mais bon', '2026-06-04 22:19:00+00', 'safe'),
    ('m0000010-0000-0000-0072-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'Il dit la même chose de toi au fait', '2026-06-04 22:21:00+00', 'safe'),
    ('m0000010-0000-0000-0073-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'JE SUIS CHOQUÉE. Laquelle des deux choses', '2026-06-04 22:22:00+00', 'safe'),
    ('m0000010-0000-0000-0074-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'Que t''es chiante 😇', '2026-06-04 22:23:00+00', 'safe'),
    ('m0000010-0000-0000-0075-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'Traître', '2026-06-04 22:24:00+00', 'safe'),
    ('m0000010-0000-0000-0076-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'haha. Non sérieux, il t''adore. Il a dit : "Alice c''est le genre de personne qui te dit ses quatre vérités mais t''en veux jamais"', '2026-06-04 22:25:00+00', 'safe'),
    ('m0000010-0000-0000-0077-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', '...', '2026-06-04 22:27:00+00', 'safe'),
    ('m0000010-0000-0000-0078-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'ok ça m''a touché je vais pas mentir', '2026-06-04 22:27:00+00', 'safe'),
    ('m0000010-0000-0000-0079-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'T''as le droit', '2026-06-04 22:28:00+00', 'safe'),
    ('m0000010-0000-0000-0080-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'T''es comment toi avec tes amis proches ? T''as des Julien dans ta vie ?', '2026-06-04 22:29:00+00', 'safe'),
    ('m0000010-0000-0000-0081-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'Mmh. J''en ai un, Mathieu, on se connaît depuis la fac. Mais on se voit moins depuis qu''il a eu un enfant', '2026-06-04 22:31:00+00', 'safe'),
    ('m0000010-0000-0000-0082-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'C''est dur ça. L''enfant ça change tout dans une amitié', '2026-06-04 22:33:00+00', 'safe'),
    ('m0000010-0000-0000-0083-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'Ouais. C''est pas mauvais, juste… différent. On s''adapte', '2026-06-04 22:34:00+00', 'safe'),
    ('m0000010-0000-0000-0084-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'T''as l''air de le gérer bien quand même', '2026-06-04 22:36:00+00', 'safe'),
    ('m0000010-0000-0000-0085-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'J''essaie. Des fois ça va, des fois j''ai l''impression de pas le reconnaître', '2026-06-04 22:37:00+00', 'safe'),
    ('m0000010-0000-0000-0086-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'C''est honnête ce que tu dis', '2026-06-04 22:39:00+00', 'safe'),
    ('m0000010-0000-0000-0087-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'C''est 22h passé, j''ai plus l''énergie de mentir', '2026-06-04 22:40:00+00', 'safe'),
    ('m0000010-0000-0000-0088-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'haha. Logique', '2026-06-04 22:41:00+00', 'safe'),
    ('m0000010-0000-0000-0089-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'moi à cette heure-là je deviens beaucoup plus franche aussi. C''est suspect', '2026-06-04 22:42:00+00', 'safe'),
    ('m0000010-0000-0000-0090-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'C''est la nuit qui fait ça', '2026-06-04 22:43:00+00', 'safe'),
    ('m0000010-0000-0000-0091-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'Ouais probablement', '2026-06-04 22:44:00+00', 'safe'),
    ('m0000010-0000-0000-0092-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000002', 'T''écris quoi là ?', '2026-06-04 23:02:00+00', 'safe'),
    ('m0000010-0000-0000-0093-000000000000', 'c0000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'rien je traîne. Laurent dort tôt en ce moment, il a des déplacements la semaine prochaine donc il récupère. Et toi ?', '2026-06-04 23:06:00+00', 'safe'),
